template:
{{ define "callBotImage" }}
{{- $dbms := .CommonLabels.DBMS -}}
{{- $resource := .CommonLabels.리소스 -}}
    {{- range .Alerts -}}
        {{- $target := "ServerName" -}}
        {{- $labels := .Labels -}}
        {{- with index $labels $target -}}
            {{- with $target }}<@dbamon> 실시간 {{ $dbms }} {{ $resource }} 사용량 {{ index $labels $target }} {{- "\n" }}
            {{- end -}}
        {{- end -}}
    {{- end -}}
{{- end -}}
